        sdg12_un_targets_title: `Metas ONU & Indicadores aplicáveis em Arquitetura / ODS 12 :`,
        sdg12_un_target_12_1_label: `Meta ONU 12.1:`,
        sdg12_un_target_12_1_text: `Implement the 10-year framework of programmes on sustainable consumption and production, all countries taking action, with developed countries taking the lead, taking into account the development and capabilities of developing countries`,
        sdg12_un_target_12_2_label: `Meta ONU 12.2:`,
