        sdg4_subtitle: `Assurer une éducation inclusive, équitable et de qualité !`,
        sdg4_un_targets_title: `Cibles ODD & Indicateurs applicables en Architecture / ODD 04 :`,
        sdg4_un_target_4_3_label: `Cible ODD 4.3:`,
        sdg4_un_target_4_3_text: `By 2030, ensure equal access for all women and men to affordable and quality technical, vocational and tertiary education, including university. to affordable and quality technical, vocational and tertiary education, including university .`,
        sdg4_un_target_4_a_label: `4.A:`,
        sdg4_un_target_4_a_text: `Build and upgrade education facilities that are child, disability and gender sensitive and provide safe, nonviolent, inclusive and effective learning environments for all.`,
