function translatePage() {
    const lang = translations[currentLanguage] || translations['en'];
    const fallback = translations['en'];
    document.querySelectorAll('[data-translate-key]').forEach(element => {
        const key = element.getAttribute('data-translate-key');
        const text = (lang && lang[key]) || (fallback && fallback[key]);
        if (!text) return;
        if (element.tagName === 'INPUT' && (element.type === 'text' || element.type === 'search')) {
            element.placeholder = text;
        } else if (element.tagName === 'TEXTAREA') {
            element.placeholder = text;
        } else {
            element.textContent = text;
        }
    });
}

function setLanguage(lang) {
    if (!translations[lang]) { console.error('Language ' + lang + ' not supported'); return; }
    currentLanguage = lang;
    localStorage.setItem('sdgAssessmentLang', lang);
    document.querySelectorAll('.lang-btn').forEach(btn => {
        btn.classList.toggle('lang-btn-active', btn.getAttribute('data-lang') === lang);
    });
    translatePage();
    if (typeof updateNavigationButtonText === 'function') updateNavigationButtonText();
}

document.addEventListener('DOMContentLoaded', () => {
    const saved = localStorage.getItem('sdgAssessmentLang') || 'en';
    setLanguage(saved);
});

if (typeof module !== 'undefined' && module.exports) module.exports = translations;
